#!/bin/bash

# Define the audit rule
AUDIT_RULE="-a always,exit -F path=/usr/lib/openssh/ssh-keysign -F perm=x -F auid>=1000 -F auid!=unset -k privileged"

# Function to check if the rule is already present
check_rule() {
    auditctl -l | grep -q -- "$AUDIT_RULE"
}

# Function to add the rule to the audit rules file
add_rule_to_file() {
    local rules_file="/etc/audit/rules.d/privileged.rules"
    grep -q -- "$AUDIT_RULE" "$rules_file" || echo "$AUDIT_RULE" >> "$rules_file"
}

# Function to reload audit rules
reload_audit_rules() {
    if pgrep -x "auditd" > /dev/null; then
        augenrules --load
    fi
}

# Main logic
if ! check_rule; then
    add_rule_to_file
    reload_audit_rules
fi
